import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import axios from "axios";
import "./App.css";

const SERVER_URL = process.env.REACT_APP_SERVER_URL || "http://localhost:3001";
const socket = io(SERVER_URL, { transports: ["websocket"] });

const EMOJIS = ["❤️", "😂", "👍", "😮", "😢"];

const DoubleCheck = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="tick-icon double" viewBox="0 0 24 24">
    <path d="M3 12l5 5L20 5" fill="none" stroke="#00e5ff" strokeWidth="2" />
    <path d="M9 12l5 5L23 5" fill="none" stroke="#00e5ff" strokeWidth="2" />
  </svg>
);

const SingleCheck = () => (
  <svg xmlns="http://www.w3.org/2000/svg" className="tick-icon single" viewBox="0 0 24 24">
    <path d="M4 12l5 5L20 7" fill="none" stroke="gray" strokeWidth="2" />
  </svg>
);

function App() {
  const [username, setUsername] = useState(null);
  const [token, setToken] = useState(null);
  const [form, setForm] = useState({ username: "", email: "", password: "" });
  const [mode, setMode] = useState("login");
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);
  const [activeReaction, setActiveReaction] = useState(null);
  const messagesEndRef = useRef(null);
  const typingTimeout = useRef(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  const isNearBottom = () => {
    const el = messagesEndRef.current?.parentNode;
    if (!el) return false;
    return el.scrollHeight - el.scrollTop - el.clientHeight < 100;
  };

  useEffect(() => {
    const storedUser = localStorage.getItem("chatUser");
    const storedToken = localStorage.getItem("chatToken");
    if (storedUser && storedToken) {
      setUsername(storedUser);
      setToken(storedToken);
      socket.emit("joinRoom", { username: storedUser });
    }
  }, []);

  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post(`${SERVER_URL}/${mode}`, form);
      localStorage.setItem("chatUser", res.data.username);
      localStorage.setItem("chatToken", res.data.token);
      setUsername(res.data.username);
      setToken(res.data.token);
      socket.emit("joinRoom", { username: res.data.username });
    } catch (err) {
      alert(err.response?.data?.error || "Authentication failed");
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    setUsername(null);
    setToken(null);
  };

  // --- Socket Listeners ---
  useEffect(() => {
    socket.on("receiveMessage", (msg) => {
      setMessages((prev) => [...prev, msg]);
      if (isNearBottom()) setTimeout(scrollToBottom, 100);
      socket.emit("markAsRead", { username });
    });

    socket.on("messageRead", (updated) => setMessages(updated));
    socket.on("messageUpdated", (updatedMsg) =>
      setMessages((prev) =>
        prev.map((m) => (m._id === updatedMsg._id ? updatedMsg : m))
      )
    );

    socket.on("onlineUsers", (users) => setOnlineUsers(users));
    socket.on("typing", (user) => setTypingUser(user));
    socket.on("stopTyping", () => setTypingUser(null));

    return () => {
      socket.off("receiveMessage");
      socket.off("messageRead");
      socket.off("messageUpdated");
      socket.off("onlineUsers");
      socket.off("typing");
      socket.off("stopTyping");
    };
  }, [username]);

  // --- Fetch messages ---
  useEffect(() => {
    if (!username) return;
    const fetchMessages = async () => {
      const res = await axios.get(`${SERVER_URL}/messages`);
      setMessages(res.data);
      setTimeout(scrollToBottom, 100);
      socket.emit("markAsRead", { username });
    };
    fetchMessages();
  }, [username]);

  // --- Send message ---
  const sendMessage = (e) => {
    e.preventDefault();
    if (!text.trim()) return;
    socket.emit("sendMessage", { username, text });
    setText("");
  };

  // --- Typing indicator ---
  const handleTyping = (e) => {
    setText(e.target.value);
    socket.emit("typing", username);
    clearTimeout(typingTimeout.current);
    typingTimeout.current = setTimeout(() => socket.emit("stopTyping"), 1000);
  };

  // --- Emoji reactions ---
  const toggleReactionPicker = (id) => {
    setActiveReaction((prev) => (prev === id ? null : id));
  };

  const sendReaction = (id, emoji) => {
    socket.emit("reactMessage", { messageId: id, username, emoji });
    setActiveReaction(null);
  };

  if (!username) {
    return (
      <div className="app">
        <div className="login">
          <h2>{mode === "login" ? "Login" : "Signup"}</h2>
          <form onSubmit={handleAuth}>
            <input
              placeholder="Username"
              onChange={(e) => setForm({ ...form, username: e.target.value })}
            />
            {mode === "signup" && (
              <input
                placeholder="Email"
                onChange={(e) => setForm({ ...form, email: e.target.value })}
              />
            )}
            <input
              type="password"
              placeholder="Password"
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />
            <button type="submit">{mode === "login" ? "Login" : "Signup"}</button>
          </form>
          <button onClick={() => setMode(mode === "login" ? "signup" : "login")}>
            Switch to {mode === "login" ? "Signup" : "Login"}
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>Welcome, {username}</h2>
        <button onClick={handleLogout}>Logout</button>
      </div>

      <div className="chat-main">
        <div className="sidebar">
          <h4>Online</h4>
          <ul>{onlineUsers.map((u, i) => <li key={i}>{u}</li>)}</ul>
        </div>

        <div className="messages-area">
          {messages.map((msg) => {
            const isMine = msg.username === username;
            const isRead = msg.readBy?.length > 1;

            return (
              <div key={msg._id} className={`message ${isMine ? "me" : "other"}`}>
                <div className="text">
                  {!isMine && <strong>{msg.username}: </strong>} {msg.text}
                  <span className="timestamp">
                    {new Date(msg.createdAt).toLocaleTimeString([], {
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                    {isMine && (isRead ? <DoubleCheck /> : <SingleCheck />)}
                  </span>

                  {msg.reactions?.length > 0 && (
                    <div className="reactions">
                      {msg.reactions.map((r, idx) => (
                        <span
                          key={idx}
                          className={`reaction ${
                            r.users.includes(username) ? "mine" : ""
                          }`}
                          onClick={() => sendReaction(msg._id, r.emoji)}
                        >
                          {r.emoji} {r.users.length > 1 ? r.users.length : ""}
                        </span>
                      ))}
                    </div>
                  )}

                  {!isMine && (
                    <div
                      className={`reaction-btn ${
                        activeReaction === msg._id ? "active" : ""
                      }`}
                      onClick={(e) => {
                        e.stopPropagation();
                        toggleReactionPicker(msg._id);
                      }}
                    >
                      😊
                      {activeReaction === msg._id && (
                        <div className="emoji-picker">
                          {EMOJIS.map((emoji) => (
                            <span
                              key={emoji}
                              onClick={() => sendReaction(msg._id, emoji)}
                            >
                              {emoji}
                            </span>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            );
          })}

          <div ref={messagesEndRef} />
          {typingUser && <div className="typing">{typingUser} is typing...</div>}

          <form className="composer" onSubmit={sendMessage}>
            <textarea
              value={text}
              onChange={handleTyping}
              placeholder="Type a message..."
            />
            <button type="submit">Send</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default App;
